insert into public.packages
  (slug, name, category, description, image, price, days, nights,
   route, highlights, featured, rating)
values
  ('ladakh-high-passes', 'Ladakh High Passes Expedition', 'adventure',
   'Khardung La, Nubra''s dunes and a lakeshore camp at Pangong — oxygen-equipped SUVs and crews that know every hairpin.',
