insert into public.testimonials (name, origin, avatar, rating, quote, trip_name)
select * from (values
  ('Ananya & Dev Iyer', 'Bengaluru, India', 'https://randomuser.me/api/portraits/women/44.jpg', 5.0, 'Aurevia didn''t plan our honeymoon — they directed it. Every sunset seemed to arrive on cue. We came home different people.', 'Maldives Celebration'),
  ('James Whitmore', 'London, UK', 'https://randomuser.me/api/portraits/men/32.jpg', 5.0, 'I''ve used travel designers on four continents. Nobody sweats the details like this team — the houseboat playlist matched the sunset.', 'Spice Coast Immersion'),
  ('Farah Sheikh', 'Dubai, UAE', 'https://randomuser.me/api/portraits/women/68.jpg', 4.9, 'Ladakh at those altitudes could have been an ordeal. Instead it was the most comfortable adventure of my life.', 'High Passes Expedition'),
  ('The Gupta Family', 'Ahmedabad, India', 'https://randomuser.me/api/portraits/men/75.jpg', 4.8, 'Two kids, four grandparents, zero meltdowns. Singapore with Aurevia was the first holiday where we all actually rested.', 'Singapore Family Week'),
  ('Charlotte Dubois', 'Paris, France', 'https://randomuser.me/api/portraits/women/17.jpg', 5.0, 'The balloon over Amber at dawn, the palace dinner by oil lamp — Jaipur was staged like an opera and we had the royal box.', 'Royal Rajasthan'),
  ('Rajeev Talwar', 'New Delhi, India', 'https://randomuser.me/api/portraits/men/54.jpg', 5.0, 'Excellence Class on the Glacier Express, arranged down to the window side. Switzerland by Aurevia is the only way I''ll do it again.', 'Alpine Grand Tour')
) as v(name, origin, avatar, rating, quote, trip_name)
where not exists (select 1 from public.testimonials where deleted_at is null);

insert into public.faqs (question, answer, category)
select * from (values
  ('How far in advance should I book my journey?', 'For international journeys and peak seasons (December–January, April–May) we recommend 60–90 days, which secures the best villas, rail classes and guides. Domestic escapes can often be arranged within two to three weeks. For the Maldives and Switzerland in high season, earlier is always better.', 'Booking'),
  ('Are your itineraries customisable?', 'Entirely. Every published itinerary is a starting sketch — our travel designers rebuild it around your dates, pace, cuisine preferences and occasions. Roughly 80% of the journeys we operate are bespoke variations of our core routes.', 'Booking'),
  ('What is included in the published price?', 'Each destination page lists inclusions and exclusions precisely. As a rule: stays, private transfers, named experiences, listed meals and your destination host are included; flights to the starting point, visas and insurance are not. There are no hidden fees — the quote you approve is the price you pay.', 'Pricing'),
  ('How do payments and cancellations work?', 'A 25% deposit confirms your journey; the balance is due 30 days before departure. Cancellations more than 45 days out are refunded minus non-recoverable supplier costs; within 45 days, our team works to recover and re-credit whatever the hotels and operators allow. We always recommend comprehensive travel insurance.', 'Pricing'),
  ('Do you assist with visas and travel insurance?', 'Yes. Our documentation desk prepares your visa file, books appointments and tracks applications for every destination we operate. We also partner with leading insurers for trip, medical and high-altitude cover, and will recommend the right policy for your route.', 'Travel'),
  ('Is support available while I''m travelling?', 'Every journey runs with a dedicated destination host and a 24/7 concierge line. Flight delayed, weather turned, restaurant closed — one message and the itinerary reshapes around you in real time.', 'Travel'),
  ('Can you arrange journeys for large families or corporate groups?', 'Group journeys are a speciality — multi-generation family reunions, incentive trips, offsites and destination celebrations up to 120 guests. We handle rooming, dietaries, staggered arrivals, event production and on-ground crew.', 'Groups'),
  ('Which destinations suit first-time international travellers?', 'Singapore, Dubai and Thailand are our gentlest introductions — short flights from India, simple visas, and infrastructure that forgives every wrong turn. Bali follows closely for couples. Our designers will match the destination to your comfort level.', 'Travel')
) as v(question, answer, category)
where not exists (select 1 from public.faqs where deleted_at is null);
